import React, { useState, useEffect, useRef } from 'react';
import logo from './logo.svg';
import './App.css';

function App() {
  const [displayText, setDisplayText] = useState('');
  const terminalRef = useRef(null);
  const [cursorVisible, setCursorVisible] = useState(true);

  useEffect(() => {
    const terminalOutputs = [
      'Windows PowerShell',
      'Copyright (C) Microsoft Corporation. All rights reserved.',
      '',
      'PS C:\\users\\Admin> ',
    ];

    const typingText = 'My Name is Nathaniel';
    const highlightedWord = 'Nathaniel';
    const cursorSymbol = '>';
    let currentIndex = 0;

    const typeText = () => {
      if (currentIndex < typingText.length) {
        const currentText = terminalOutputs[3] + cursorSymbol + typingText.substring(0, currentIndex);
        setDisplayText(terminalOutputs.slice(0, 3).join('\n') + '\n' + currentText);

        currentIndex++;

        terminalRef.current.scrollTop = terminalRef.current.scrollHeight;

        setTimeout(typeText, 200);
      } else {
        setTimeout(() => {
          const underlineText = terminalOutputs[3] + cursorSymbol + `<span style="text-decoration: underline; color: red;">${highlightedWord}</span>`;
          setDisplayText(terminalOutputs.slice(0, 3).join('\n') + '\n' + underlineText);
          setTimeout(() => {
            const grayText = terminalOutputs[3] + cursorSymbol + `<span style="color: gray;">${typingText}</span>`;
            setDisplayText(terminalOutputs.slice(0, 3).join('\n') + '\n' + grayText);
            setTimeout(() => {
              setDisplayText(terminalOutputs.slice(0, 3).join('\n'));
              setTimeout(() => {
                setDisplayText(terminalOutputs.slice(0, 3).join('\n') + '\nBut People Call me Nate');
              }, 1000);
            }, 1000);
          }, 2000);
        }, 1000);
      }
    };

    setDisplayText(terminalOutputs.join('\n'));

    terminalRef.current.scrollTop = terminalRef.current.scrollHeight;

    const cursorInterval = setInterval(() => {
      setCursorVisible((prevVisible) => !prevVisible);
    }, 500);

    setTimeout(typeText, 2000);

    return () => {
      clearInterval(cursorInterval);
    };
  }, []);

  return (
    <div className="App">
      <header className="App-header">
        <img src={logo} className="App-logo" alt="logo" />
        <div className="terminal" ref={terminalRef}>
          <pre dangerouslySetInnerHTML={{ __html: displayText }} />
          {cursorVisible && <span className="cursor">|</span>}
        </div>
      </header>
    </div>
  );
}

export default App;
